    background:rgba(255,255,255,.9);
    box-shadow:var(--aap-shadow);
  }

  .aap-contact-v1 .aap-proof-card strong{
    display:block;
    margin-bottom:6px;
    color:var(--aap-navy);
    font-size:15px;
  }

  .aap-contact-v1 .aap-proof-card span{
    color:var(--aap-slate);
    font-size:14px;
    line-height:1.65;
  }

  .aap-contact-v1 .aap-form-card{
    padding:28px;
    border-radius:24px;
    background:
      radial-gradient(circle at top right, rgba(31,95,168,.10), transparent 28%),
      radial-gradient(circle at bottom left, rgba(207,135,84,.10), transparent 24%),
      linear-gradient(180deg,#ffffff 0%, #f2f8fc 100%);
