      <div class="aap-footer">
        <a class="aap-btn primary" href="/contact-us/">Talk Through Your Current Bottlenecks</a>
        <a class="aap-btn secondary" href="/resources/">Explore More Resources</a>
      </div>
    </div>
  </div>
</section>

<script>
(function(){
  var target = document.getElementById('aap-blog-feed-results');
  if (!target) return;

  var endpoint = window.location.origin + '/wp-json/wp/v2/posts?_embed&per_page=6';

  function formatDate(dateString){
    try{
      return new Date(dateString).toLocaleDateString('en-US', {
        year: 'numeric',
        month: 'long',
        day: 'numeric'
      });
    } catch(e){
      return '';
    }
  }

  function decodeHTML(html){
    var txt = document.createElement('textarea');
    txt.innerHTML = html;
    return txt.value;
  }

  function stripHTML(html){
    var div = document.createElement('div');
    div.innerHTML = html;
    return (div.textContent || div.innerText || '').trim();
  }

  function trimExcerpt(text, max){
    if (text.length <= max) return text;
    return text.slice(0, max).replace(/\s+\S*$/, '') + '...';
  }

  fetch(endpoint)
    .then(function(res){
      if(!res.ok) throw new Error('Failed to load posts');
      return res.json();
    })
    .then(function(posts){
      if(!posts || !posts.length){
        target.className = 'aap-empty';
        target.innerHTML = 'No blog posts are published yet. Once you begin publishing articles in WordPress, the latest posts will appear here automatically.';
        return;
      }

      var html = '<div class="aap-grid">';
      posts.forEach(function(post){
        var title = decodeHTML(post.title && post.title.rendered ? post.title.rendered : 'Untitled');
        var excerpt = trimExcerpt(stripHTML(post.excerpt && post.excerpt.rendered ? post.excerpt.rendered : ''), 180);
        var link = post.link || '#';
        var date = formatDate(post.date);
        var image = '';
        if (
          post._embedded &&
          post._embedded['wp:featuredmedia'] &&
          post._embedded['wp:featuredmedia'][0] &&
          post._embedded['wp:featuredmedia'][0].source_url
        ) {
          image = post._embedded['wp:featuredmedia'][0].source_url;
        }

        html += '<article class="aap-card">';
        if (image) {
          html += '<a class="aap-thumb" href="' + link + '"><img src="' + image + '" alt="' + title.replace(/"/g, '&quot;') + '"></a>';
        } else {
          html += '<a class="aap-thumb" href="' + link + '"></a>';
        }
        html += '<div class="aap-body">';
        html += '<div class="aap-meta">' + date + '</div>';
        html += '<h3><a href="' + link + '">' + title + '</a></h3>';
        if (excerpt) {
          html += '<p class="aap-excerpt">' + excerpt + '</p>';
        }
        html += '<div class="aap-spacer"></div>';
        html += '<a class="aap-link" href="' + link + '">Read article</a>';
        html += '</div></article>';
      });
      html += '</div>';

      target.className = '';
      target.innerHTML = html;
    })
    .catch(function(){
      target.className = 'aap-empty';
      target.innerHTML = 'The article feed is temporarily unavailable right now. Published posts should still be available through the site blog and resources area.';
    });
})();
</script>
